from matplotlib import pyplot as plt"""------------------------------------------------------------------------------------------------------- Utility functions used throughout the CRIRESViz plotting backend. ----------------------------------------------------------------------------------------------------------"""def prepare_axes(ax=None, wavelength_range=None):    """    Create or initialize a plotting axis.    Parameters    ----------    ax : matplotlib.axes.Axes, optional        Existing axis to use. If None, a new figure and axis are created.    wavelength_range : tuple(float, float), optional        Initial wavelength limits.    Returns    -------    fig : matplotlib.figure.Figure        Figure containing the axis.    ax : matplotlib.axes.Axes        Initialized plotting axis.    """            if ax is None:        fig, ax = plt.subplots(figsize=(12, 6))    else:        fig = ax.figure    if wavelength_range is not None and not ax.has_data():        xmin, xmax = wavelength_range        padding = 0.06 * (xmax - xmin)        ax.set_xlim(xmin-padding, xmax+padding)            ax.set_ylim(0, 1.1)    return fig, ax    ##############################################    def update_xlim(ax, wavelength_range):    """    Expand the x-axis limits to include a wavelength range.    Parameters    ----------    ax : matplotlib.axes.Axes        Axis to update.    wavelength_range : tuple(float, float)        Wavelength interval to include.    """    xmin, xmax = wavelength_range        padding = 0.06 * (xmax - xmin)    if not ax.has_data():        ax.set_xlim(xmin-padding, xmax+padding)        return    current_min, current_max = ax.get_xlim()    ax.set_xlim(        min(current_min, xmin-padding),        max(current_max, xmax+padding),    )    def update_ylim(ax, n_molecules, spacing=0.05):    """    Increase the y-axis limits to leave room for molecule annotations.    Parameters    ----------    ax : matplotlib.axes.Axes        Axis to update.    mol_num : int        Number of molecule bars to display.    spacing : float, optional        Vertical spacing between adjacent molecule bars.    """        top = 1.1 + n_molecules * spacing    ax.set_ylim(0, top) ##############################################    def style_axes(ax):    """    Apply the default CRIRESViz axis style.        This configures inward-facing major and minor ticks on both axes.    """    ax.minorticks_on()    ax.tick_params(        axis="x",        which="major",        direction="inout",        length=5,    )    ax.tick_params(        axis="x",        which="minor",        direction="inout",        length=3,    )    ax.tick_params(        axis="y",        which="major",        direction="inout",        length=5,    )    ax.tick_params(        axis="y",        which="minor",        direction="inout",        length=3,    )##############################################def make_compact_axes(settings, figsize=(12, 6)):    """    Create one axis per CRIRES+ setting.    Parameters    ----------    settings : list[CRIRESSetting]    figsize : tuple(float, float), optional    Figure size passed to matplotlib.    Returns    -------    fig : matplotlib.figure.Figure    axes : list[matplotlib.axes.Axes]    """    n = len(settings)            widths = [        s.wavelength_range[1] - s.wavelength_range[0]        for s in settings    ]    fig, axes = plt.subplots(        1,        n,        gridspec_kw={"width_ratios": widths, "wspace": 0.05,},        figsize=figsize,        sharey=True,        squeeze=False,    )    axes = axes.flatten()    for ax, setting in zip(axes, settings):        xmin, xmax = setting.wavelength_range        padding = 0.06 * (xmax - xmin)        ax.set_xlim(            xmin - padding,            xmax + padding,        )        ax.set_ylim(0, 1.1)            return fig, list(axes)##############################################def style_compact_axes(axes, settings, padding=0.02):    """    Apply the CRIRESViz style to a compact multi-panel wavelength plot.    Parameters    ----------    axes : list[matplotlib.axes.Axes]        Axes composing the compact layout.    settings : list[CRIRESSetting]        Settings displayed on each axis.    padding : float, optional        Fractional padding added to the wavelength limits.    """    for i, (ax, setting) in enumerate(zip(axes, settings)):        xmin, xmax = setting.wavelength_range        dx = xmax - xmin                ax.set_xlim(            xmin - padding*dx,            xmax + padding*dx,        )                        style_axes(ax)                if i!=0:            ax.spines["left"].set_visible(False)            ax.tick_params(axis="y", which="both", left=False, labelleft=False, length=0)        if(i!=len(axes)-1):            ax.spines["right"].set_visible(False)                        # Hide touching spines    for left, right in zip(axes[:-1], axes[1:]):        left.spines["right"].set_visible(False)        right.spines["left"].set_visible(False)                                  ##############################################        def add_break_marks(axes, size=0.02):    """    Draw break marks between adjacent compact-layout axes.    Parameters    ----------    axes : list[matplotlib.axes.Axes]        Consecutive axes composing the compact layout.    size : float, optional        Relative size of the break marks in axes coordinates.    """        kwargs = dict(        color="k",        clip_on=False,        linewidth=1,    )    for left, right in zip(axes[:-1], axes[1:]):        # right edge of left axis        left.plot(            (1, 1),            (-size, +size),            transform=left.transAxes,            **kwargs,        )        left.plot(            (1, 1),            (1-size, 1+size),            transform=left.transAxes,            **kwargs,        )        # left edge of right axis        right.plot(            (0, 0),            (-size, +size),            transform=right.transAxes,            **kwargs,        )        right.plot(            (0, 0),            (1-size, 1+size),            transform=right.transAxes,            **kwargs,        )